class Solution {
public:
    int longestPalindrome(string s, string t) {
        unordered_map<char, int> s_count, t_count;
        for (char c : s) s_count[c]++;
        for (char c : t) t_count[c]++;

        int common = 0, odd = 0;
        for (auto& pair : s_count) {
            if (t_count.count(pair.first)) {
                common += min(pair.second, t_count[pair.first]);
                if (pair.second % 2 == 1 && t_count[pair.first] % 2 == 1) odd = 1;
            }
        }

        return common * 2 + odd;
    }
};
